import http.client
import json


conn = http.client.HTTPSConnection("192.168.0.1")
payload = json.dumps({
  "management": "string",
  "name": "Default Network",
  "enabled": True,
  "vlanId": 0,
  "dhcpGuarding": {
    "trustedDhcpServerIpAddresses": [
      "string"
    ]
  }
})
headers = {
  'Accept': 'application/json',
  'X-API-Key': '<X-API-Key>',
  'Content-Type': 'application/json'
}
conn.request("PUT", "/proxy/network/integration/v1/sites/{siteId}/networks/{networkId}", payload, headers)
res = conn.getresponse()
data = res.read()
print(data.decode("utf-8"))

